class Solution {
public:
    string reverseWords(string s) {
        istringstream iss(s);
        string word, result;
        while (iss >> word) {
            reverse(word.begin(), word.end());
            result += word + " ";
        }
        result.pop_back(); // remove the trailing space
        return result;
    }
};
```
